@ARTICLE{10.26803/ijlter.24.9.21,
	author = {Zhang, Q. and Amat, S. and Omar, M. and Mansor, A.Z.},
	title = {Predicting Career Adaptability among Higher Vocational College Students: The Roles of Proactive Personality, Career Decision-Making Self-Efficacy, and Social Support},
	journal = {International Journal of Learning, Teaching and Educational Research},
	year = {2025},
	abstract = {This study examined how proactive personality, career decision-making self-efficacy, and social support influence career adaptability among higher vocational college students in Sichuan Province, China. Guided by Career Construction Theory and Social Cognitive Career Theory, the research addressed a critical gap in understanding the interplay of individual traits and contextual factors in shaping career readiness within Chinese vocational education. A cross-sectional survey was conducted with 382 students selected through proportional stratified random sampling across four institutions. Validated instruments were used to measure each construct, and data were analysed using Pearson correlation and multiple linear regression. The results showed that all three predictors were significantly and positively related to career adaptability: proactive personality (β = .24, p < .001), career decision-making self-efficacy (β = .23, p < .001), and social support (β = .37, p < .001). The full model accounted for 53% of the variance in career adaptability, with social support emerging as the strongest predictor. These findings reinforce the applicability of both Career Construction Theory and Social Cognitive Career Theory in non-Western, collectivist contexts and underscore the combined developmental and environmental influences on vocational students’ career outcomes. Practically, the study highlights the need for integrated, student-centred interventions that strengthen proactive behaviours, enhance self-efficacy, and build supportive networks to promote adaptable and confident career transitions. ©Authors. ER - ER - ER -},
	doi = {10.26803/ijlter.24.9.21},
	type = {JOUR}
}

@ARTICLE{10.3390/bs15020167,
	author = {Xu, M. and Lu, H. and Fu, J. and Zhu, H. and Zhao, Y.},
	title = {The Relationship Between Basic Psychological Needs Satisfaction and Career Adaptability Among University Students: The Roles of Grit and Career Decision-Making Self-Efficacy},
	journal = {Behavioral Sciences},
	year = {2025},
	keywords = {basic psychological needs satisfaction; career adaptability; grit; career decision-making self-efficacy; university students; CONSTRUCTION; CHOICE ER - ER - ER -},
	abstract = {Enhancing the career adaptability of university students is a practical necessity for addressing the challenge of student employment. This study explores the relationship between basic psychological needs satisfaction and career adaptability among university students based on Basic Psychological Need Theory and Social Cognitive Career Theory and constructs a corresponding chain mediation model. A survey was conducted among 635 university students from six provinces across China. The results indicate the following findings: (1) grit partially mediates the relationship between basic psychological needs satisfaction and career adaptability among university students; (2) career decision-making self-efficacy also partially mediates this relationship; and (3) grit and career decision-making self-efficacy serve as chain mediators in the relationship between basic psychological needs satisfaction and career adaptability. This study provides empirical support and significant guidance for enhancing the career adaptability development of university students. © 2025 by the authors.},
	doi = {10.3390/bs15020167},
	type = {JOUR}
}

@ARTICLE{10.3390/su13126817,
	author = {Shen, X. and Gu, X. and Chen, H. and Wen, Y.},
	title = {For the future sustainable career development of college students: Exploring the impact of core self-evaluation and career calling on career decision-making difficulty},
	journal = {Sustainability (Switzerland)},
	year = {2021},
	keywords = {Chinese college students; career decision-making difficulties; core self-evaluation; career calling; mediating role; sustainable development; PERSONALITY-RELATED ASPECTS; JOB-SATISFACTION; EMOTIONAL INTELLIGENCE; TRAITS; EFFICACY; INDIVIDUALISM; QUESTIONNAIRE; ADAPTABILITY; PERFORMANCE; VALIDATION ER - ER - ER -},
	abstract = {As one of the important factors to predict future sustainable development, the difficulty of career decision-making has aroused widespread concern in psychological research. Core self-evaluation and career calling have a positive impact on college students’ career development, em-ployees’ organizational behavior, life satisfaction, and life meaning, thus promoting individual sustainable development. Based on the Social Cognitive Career Theory (SCCT), this study mainly dis-cusses the positive role of core self-evaluation and career calling in overcoming college students’ career decision-making difficulties, which provides support for strengthening theory and proposing educational countermeasures. This study investigates the relationship among core self-evaluation, career calling, and career decision-making difficulties for 483 Chinese college students. The results show that core self-evaluation positively predicts career calling, while core self-evaluation and career calling negatively predict career decision-making difficulties. Accordingly, career calling plays a partial mediating role between core self-evaluation and career decision-making difficulties. There-fore, college students’ career calling can be enhanced by improving their core self-evaluation, so as to further solve the difficulties in career decision-making. In the future, effective strategies should be taken to reduce the career decision-making difficulty for students’ sustainable development. © 2021 by the authors. Li-censee MDPI, Basel, Switzerland.},
	doi = {10.3390/su13126817},
	type = {JOUR}
}

@ARTICLE{10.3390/bs15030260,
	author = {Xiong, Z. and Zeng, M. and Xu, Y. and Gao, B. and Shen, Q.},
	title = {Linking Career-Related Social Support to Job Search Behavior Among College Students: A Moderated Mediation Model},
	journal = {Behavioral Sciences},
	year = {2025},
	keywords = {career-related social support; career decision-making self-efficacy; employment pressure; job search behavior; college students; MAKING SELF-EFFICACY; PARENTAL BEHAVIORS; PLANNED BEHAVIOR; COGNITIVE THEORY; ADAPTABILITY; EMPLOYMENT; PERSONALITY; INTENTIONS; RESOURCES; AUTONOMY ER - ER - ER -},
	abstract = {Background: Career-related social support (CRSS) significantly influences job search behavior (JSB). However, the mechanisms and boundary conditions through which CRSS impacts JSB, particularly during the COVID-19 pandemic, remain unclear. This study examines the mechanisms and boundary conditions through which CRSS influences the JSB among final-year college students during the COVID-19 pandemic, guided by social cognitive career theory (SCCT). Methods: A cross-sectional online survey was conducted in 2021 among 596 final-year college students from two public universities in China, during the COVID-19 pandemic. The survey collected data on CRSS, CDMS, employment pressure, and JSB. Results: The findings revealed that career decision-making self-efficacy (CDMS) partially mediates the relationship between CRSS and JSB. Moreover, employment pressure moderates both the direct and mediated pathways; when employment pressure is low, CRSS does not significantly enhance JSB, whereas under a high employment pressure, JSB significantly increases, with higher CRSS. In the mediated pathway, higher CDMS strongly predicts JSB under low employment pressure, but its influence diminishes as the employment pressure rises. Conclusions: These findings underscore the critical roles of CDMS and employment pressure in shaping JSB, offering valuable insights for career support initiatives to facilitate the transition of graduates into the workforce during challenging periods. © 2025 by the authors.},
	doi = {10.3390/bs15030260},
	type = {JOUR}
}

@ARTICLE{10.1016/j.jvb.2022.103838,
	author = {Morris, T.R. and Lent, R.W.},
	title = {Revisiting the bottleneck hypothesis: The role of sexual identity development in the career exploration and decision-making of sexual minority college students},
	journal = {Journal of Vocational Behavior},
	year = {2023},
	keywords = {LGBTQ; Sexual identity development; College students; Social cognitive career theory; Career self-management model; SELF-MANAGEMENT; SOCIAL SUPPORT; GAY; INDECISION; EFFICACY; STRESS; MODEL ER - ER - ER -},
	abstract = {Hetherington's (1991) “bottleneck hypothesis”, which maintains that the process of sexual identity development can hamper the career development of sexual minority college students, has received periodic study. We revisited this hypothesis using the social cognitive model of career self-management (CSM; Lent & Brown, 2013) as a theoretical framework. An online survey of 225 sexual minority and 287 heterosexual college students did not reveal a robust between-group bottleneck effect. For example, no significant mean level differences were observed between the two groups in career decision-making process and outcome variables, such as career decision-making anxiety and level of career decidedness. In addition, a CSM-based path model of career decision-making was found to be invariant across the two student groups. However, a few noteworthy within-group patterns were observed. For example, a cluster analysis suggested the presence of two sexual minority sub-groups who differed regarding level of outness and difficulties negotiating their sexual identity. The more identity-integrated cluster reported less decisional anxiety and greater decidedness than their less identity-integrated peers. Indicators of identity conflict and level of disclosure were also linked to perceived support and goals for future career exploration. The pattern of findings suggests that sexual minority identity development in college does not represent a monolithic bottleneck to career development. However, a more nuanced bottleneck effect in career decision-making may be linked to students' intrapersonal and social comfort in negotiating their sexual minority identity. Implications for the bottleneck hypothesis and further research on sexual minority students' career exploration and decision-making are discussed. © 2023 Elsevier Inc.},
	doi = {10.1016/j.jvb.2022.103838},
	type = {JOUR}
}

@ARTICLE{10.3389/fpsyg.2023.1154243,
	author = {Shi, H.},
	title = {The generation mechanism underlying the career decision-making difficulties faced by undergraduates in China during the COVID-19 pandemic: a qualitative study based on SCCT theory},
	journal = {Frontiers in Psychology},
	year = {2023},
	keywords = {career decision-making difficulties; undergraduates exhibiting delayed employment in China; COVID-19; SCCT theory; career self-management model; mind sponge theory; MEDIATING ROLE; SELF-EFFICACY; INDECISION; STUDENTS; ADAPTABILITY; SATISFACTION; CHOICE ER - ER - ER -},
	abstract = {As COVID-19 continues to spread worldwide, the record number of graduates in China and pressure resulting from the economic downturn have led to low confidence in employment among college students, and the difficulties associated with career decision-making have gradually developed into a psychological barrier to the successful employment of Chinese college students. Using the “purposive sampling” approach to qualitative research, this study selected 20 undergraduates exhibiting delayed employment from a university as our research sample and used the career self-management model of social cognitive career theory (SCCT) as an analytical framework to conduct semistructured interviews with the aim of exploring influencing factors associated with and generation mechanism underlying the career decision-making difficulties experienced by Chinese undergraduates during the COVID-19 pandemic. According to the career self-management model of SCCT theory, the four variables of individual, parents, peers and social environment influence Chinese undergraduates’ career decision-making difficulties. On this basis, this study proposes a multivariable and single-subject generation mechanism to explain undergraduates’ career decision-making difficulties and tries to explicate the mental changes associated with the career decision-making difficulties encountered by undergraduates exhibiting delayed employment by reference to mind sponge theory. Copyright © 2023 Shi.},
	doi = {10.3389/fpsyg.2023.1154243},
	type = {JOUR}
}
